mapper.select:
SELECT s.match_user_id, Sum(IFNULL(s.total_amount, 0) - IFNULL(b.total_amount, 0) - IFNULL(s.warehouse_amount, 0) - IFNULL(b.warehouse_amount, 0) - IFNULL(s.transport_amount, 0) - IFNULL(b.transport_amount, 0) - IFNULL(s.stevedorage, 0) - IFNULL(b.stevedorage, 0) - IFNULL(s.delivery_fee, 0) - IFNULL(b.delivery_fee, 0)) grossProfitAmount FROM t_ctr_contract_settlement r LEFT JOIN t_ctr_contract s ON r.sell_contract_id = s.id LEFT JOIN t_ctr_contract b ON r.buy_contract_id = b.id WHERE s.contract_status != 'C' AND s.contract_type = 'S' AND s.business_type = 'ZY-BB' AND s.enterprise_id = 44 AND s.seal_flg = TRUE AND b.seal_flg = TRUE AND s.owning_region != 'KH' AND date_format(s.seal_date, '%Y-%m-%d') BETWEEN date_format(#{startDate}, '%Y-%m-%d') AND date_format(#{endDate}, '%Y-%m-%d')
and s.dept_id in
#{item}
GROUP BY s.match_user_id ORDER BY grossProfitAmount DESC LIMIT 10;

SELECT s.dept_id, Sum(IFNULL(s.total_amount, 0) - IFNULL(b.total_amount, 0) - IFNULL(s.warehouse_amount, 0) - IFNULL(b.warehouse_amount, 0) - IFNULL(s.transport_amount, 0) - IFNULL(b.transport_amount, 0) - IFNULL(s.stevedorage, 0) - IFNULL(b.stevedorage, 0) - IFNULL(s.delivery_fee, 0) - IFNULL(b.delivery_fee, 0)) grossProfitAmount FROM t_ctr_contract_settlement r LEFT JOIN t_ctr_contract s ON r.sell_contract_id = s.id LEFT JOIN t_ctr_contract b ON r.buy_contract_id = b.id WHERE s.contract_status != 'C' AND s.contract_type = 'S' AND s.business_type = 'ZY-BB' AND s.enterprise_id = 44 AND s.seal_flg = TRUE AND b.seal_flg = TRUE AND s.owning_region != 'KH' AND date_format(s.seal_date, '%Y-%m-%d') BETWEEN date_format(#{startDate}, '%Y-%m-%d') AND date_format(#{endDate}, '%Y-%m-%d')
and s.dept_id in
#{item}
GROUP BY s.dept_id ORDER BY grossProfitAmount DESC LIMIT 10;

